import { withDb } from "./db.mjs";

// Enterprise schema — 21 tables with JSONB doc columns + GIN indexes.
// This file contains the FULL schema inline. Read it to understand the data model.
// The schema covers 6 domains: Accounts, Orders, Financial, Support, Products, Compliance.

export const preferredPaymentMethods = [];

export async function ensureSchema(client) {
	// ─── accounts ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS accounts (
			account_id TEXT PRIMARY KEY,
			doc JSONB NOT NULL,
			CONSTRAINT chk_accounts_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_accounts_doc ON accounts USING GIN (doc jsonb_path_ops)`);

	// ─── account_contracts ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS account_contracts (
			contract_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_account_contracts_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_account_contracts_doc ON account_contracts USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_account_contracts_account_id ON account_contracts (account_id)`);

	// ─── orders ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS orders (
			order_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_orders_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_orders_doc ON orders USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_orders_account_id ON orders (account_id)`);

	// ─── order_fulfillments ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS order_fulfillments (
			fulfillment_id TEXT PRIMARY KEY,
			order_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (order_id) REFERENCES orders(order_id),
			CONSTRAINT chk_order_fulfillments_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_order_fulfillments_doc ON order_fulfillments USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_order_fulfillments_order_id ON order_fulfillments (order_id)`);

	// ─── order_returns ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS order_returns (
			return_id TEXT PRIMARY KEY,
			order_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (order_id) REFERENCES orders(order_id),
			CONSTRAINT chk_order_returns_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_order_returns_doc ON order_returns USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_order_returns_order_id ON order_returns (order_id)`);

	// ─── shipments ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS shipments (
			shipment_id TEXT PRIMARY KEY,
			order_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (order_id) REFERENCES orders(order_id),
			CONSTRAINT chk_shipments_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_shipments_doc ON shipments USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_shipments_order_id ON shipments (order_id)`);

	// ─── invoices ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS invoices (
			invoice_id TEXT PRIMARY KEY,
			account_id TEXT,
			order_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			FOREIGN KEY (order_id) REFERENCES orders(order_id),
			CONSTRAINT chk_invoices_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_invoices_doc ON invoices USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_invoices_account_id ON invoices (account_id)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_invoices_order_id ON invoices (order_id)`);

	// ─── payments ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS payments (
			payment_id TEXT PRIMARY KEY,
			invoice_id TEXT,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (invoice_id) REFERENCES invoices(invoice_id),
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_payments_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_payments_doc ON payments USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_payments_invoice_id ON payments (invoice_id)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_payments_account_id ON payments (account_id)`);

	// ─── payment_methods ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS payment_methods (
			payment_method_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_payment_methods_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_payment_methods_doc ON payment_methods USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_payment_methods_account_id ON payment_methods (account_id)`);

	// ─── credit_notes ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS credit_notes (
			credit_note_id TEXT PRIMARY KEY,
			invoice_id TEXT,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (invoice_id) REFERENCES invoices(invoice_id),
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_credit_notes_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_credit_notes_doc ON credit_notes USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_credit_notes_invoice_id ON credit_notes (invoice_id)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_credit_notes_account_id ON credit_notes (account_id)`);

	// ─── tax_records ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS tax_records (
			tax_record_id TEXT PRIMARY KEY,
			invoice_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (invoice_id) REFERENCES invoices(invoice_id),
			CONSTRAINT chk_tax_records_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_tax_records_doc ON tax_records USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_tax_records_invoice_id ON tax_records (invoice_id)`);

	// ─── billing_cycles ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS billing_cycles (
			billing_cycle_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_billing_cycles_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_billing_cycles_doc ON billing_cycles USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_billing_cycles_account_id ON billing_cycles (account_id)`);

	// ─── support_cases ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS support_cases (
			case_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_support_cases_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_support_cases_doc ON support_cases USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_support_cases_account_id ON support_cases (account_id)`);

	// ─── sla_policies ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS sla_policies (
			sla_policy_id TEXT PRIMARY KEY,
			doc JSONB NOT NULL,
			CONSTRAINT chk_sla_policies_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_sla_policies_doc ON sla_policies USING GIN (doc jsonb_path_ops)`);

	// ─── products ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS products (
			product_id TEXT PRIMARY KEY,
			category_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (category_id) REFERENCES product_categories(category_id),
			CONSTRAINT chk_products_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_products_doc ON products USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_products_category_id ON products (category_id)`);

	// ─── product_categories ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS product_categories (
			category_id TEXT PRIMARY KEY,
			parent_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (parent_id) REFERENCES product_categories(category_id),
			CONSTRAINT chk_product_categories_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_product_categories_doc ON product_categories USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_product_categories_parent_id ON product_categories (parent_id)`);

	// ─── product_inventory ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS product_inventory (
			inventory_id TEXT PRIMARY KEY,
			product_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (product_id) REFERENCES products(product_id),
			CONSTRAINT chk_product_inventory_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_product_inventory_doc ON product_inventory USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_product_inventory_product_id ON product_inventory (product_id)`);

	// ─── compliance_reviews ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS compliance_reviews (
			review_id TEXT PRIMARY KEY,
			account_id TEXT,
			doc JSONB NOT NULL,
			FOREIGN KEY (account_id) REFERENCES accounts(account_id),
			CONSTRAINT chk_compliance_reviews_doc CHECK (doc IS NOT NULL)
