	await client.query(`CREATE INDEX IF NOT EXISTS idx_compliance_reviews_doc ON compliance_reviews USING GIN (doc jsonb_path_ops)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_compliance_reviews_account_id ON compliance_reviews (account_id)`);

	// ─── audit_trails ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS audit_trails (
			audit_id TEXT PRIMARY KEY,
			doc JSONB NOT NULL,
			CONSTRAINT chk_audit_trails_doc CHECK (doc IS NOT NULL)
	)`);
	await client.query(`CREATE INDEX IF NOT EXISTS idx_audit_trails_doc ON audit_trails USING GIN (doc jsonb_path_ops)`);

	// ─── data_processing_agreements ──────────────────────────────────────
	await client.query(`
		CREATE TABLE IF NOT EXISTS data_processing_agreements (
			dpa_id TEXT PRIMARY KEY,
			account_id TEXT,
